<?php require_once __DIR__.'/../../middleware/bootstrap.php';$q=$_GET;$sql='select g.*,b.name brand,c.name category,co.name country from gift_cards g left join gift_card_brands b on b.id=g.brand_id left join gift_card_categories c on c.id=g.category_id left join gift_card_countries co on co.id=g.country_id where g.enabled=1';$p=[];foreach(['country_code','currency','brand_id','category_id'] as $f){if(isset($q[$f])){$sql.=" and g.$f=?";$p[]=$q[$f];}}if(!empty($q['search'])){$sql.=' and (g.name like ? or b.name like ?)';$p[]='%'.$q['search'].'%';$p[]='%'.$q['search'].'%';}$sql.=' order by g.featured desc,g.created_at desc limit 100';$st=db()->prepare($sql);$st->execute($p);out(['products'=>$st->fetchAll()]);
